      section_1: 'Getting Started',
      section_2: 'Your Dashboard',
      section_3: 'Club Setup',
      section_4: 'Schedule &amp; Games',
      section_5: 'Roster Management',
      section_6: 'Deploying Changes',
      section_7: 'Tournament Lifecycle',
      section_8: 'Team Communication',
