      section_1: 'Demarrage',
      section_2: 'Votre tableau de bord',
      section_3: 'Configuration du club',
      section_4: 'Calendrier et matchs',
      section_5: 'Gestion du roster',
      section_6: 'Publier les changements',
      section_7: 'Cycle du tournoi',
